def defOneShift_rule(model, n, shift1, dept1, day1, shift2, dept2, day2):
    if (shift1, dept1, day1) == (shift2, dept2, day2):
        return Constraint.Skip
    start1 = value(model.startTime[shift1, dept1, day1])
    end1 = value(model.endTime[shift1, dept1, day1])
    start2 = value(model.startTime[shift2, dept2, day2])
    if start2 >= start1 and start2 < end1:
        return (
            model.nurseAssignments[n, shift1, dept1, day1]
            + model.nurseAssignments[n, shift2, dept2, day2] <= 1
        )
    return Constraint.Skip
model.defOneShift = Constraint(model.nurse, model.s, model.s, rule=defOneShift_rule)

def defNurseIncompat_rule(model, n1, n2, shift, dept, day):
    if (n1, n2) in model.nurseIncompat:
        return (
            model.nurseAssignments[n1, shift, dept, day]
            + model.nurseAssignments[n2, shift, dept, day] <= 1
        )
    return Constraint.Skip
model.defNurseIncompat = Constraint(model.nurse, model.nurse, model.s, rule=defNurseIncompat_rule)

def defNurseAssoc_rule(model, n1, n2, shift, dept, day):
    if (n1, n2) in model.nurseAssoc:
        return (
            model.nurseAssignments[n1, shift, dept, day]
            == model.nurseAssignments[n2, shift, dept, day]
        )
    return Constraint.Skip
model.defNurseAssoc = Constraint(model.nurse, model.nurse, model.s, rule=defNurseAssoc_rule)

def defSkillReq_rule(model, d, sk, shift, dept, day):
    skill_req = value(model.skillRequirements[d, sk])
    if dept == d and skill_req > 0:
        return (
            sum(
                model.nurseAssignments[n, shift, dept, day]
                for n in model.nurse
                if (n, sk) in model.nurseSkills
            ) >= skill_req
        )
    return Constraint.Skip
model.defSkillReq = Constraint(model.department, model.skill, model.s, rule=defSkillReq_rule)

def defAvgHours_rule(model):
    return len(model.nurse) * model.nurseAvgHours == sum(model.nurseWorkTime[n] for n in model.nurse)
model.defAvgHours = Constraint(rule=defAvgHours_rule)

def defOverUnderTime_rule(model, n):
